const request = require('supertest');
const { db } = require('../../src/config/database');
const { v4: uuidv4 } = require('uuid');

// 创建测试应用实例
const express = require('express');
const app = express();
app.use(express.json());

// 模拟认证中间件
const mockAuth = (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Bearer test-token-')) {
    const userId = authHeader.replace('Bearer test-token-', '');
    req.user = { id: userId };
    next();
  } else {
    res.status(401).json({ success: false, error: '认证失败' });
  }
};

// 模拟路由
app.use('/api/store', mockAuth, (req, res) => {
  // 模拟商店API响应
  if (req.method === 'GET' && req.path === '/items') {
    res.json({ success: true, data: [] });
  } else if (req.method === 'POST' && req.path === '/purchase') {
    res.json({ success: true, data: { transaction: { id: uuidv4() } } });
  } else if (req.method === 'GET' && req.path === '/inventory') {
    res.json({ success: true, data: [] });
  } else if (req.method === 'POST' && req.path === '/use') {
    res.json({ success: true });
  } else if (req.method === 'GET' && req.path === '/points') {
    res.json({ success: true, data: { points: 1000 } });
  }
});

describe('Store Controller Unit Tests', () => {
  let testUser;
  let testItem;
  let authToken;

  beforeAll(async () => {
    // 创建测试用户
    testUser = {
      id: uuidv4(),
      username: `testuser_${Date.now()}`,
      email: `test_${Date.now()}@example.com`,
      password_hash: 'hashed_password_for_test'
    };

    // 创建测试商品
    testItem = {
      id: 1, // 使用整数ID
      name: '测试商品',
      item_type: 'pixel_boost',
      price: 100, // 原始价格字段
      price_points: 100, // 积分价格字段
      active: true
    };

    // 插入测试数据
    await db('users').insert(testUser);
    await db('store_items').insert(testItem);
    
    // 创建用户积分记录
    await db('user_points').insert({
      user_id: testUser.id,
      total_points: 1000,
      created_at: new Date(),
      updated_at: new Date()
    });
  });

  afterAll(async () => {
    // 清理测试数据
    await db('users').where('id', testUser.id).del();
    await db('store_items').where('id', testItem.id).del();
    await db.destroy();
  });

  describe('GET /api/store/items', () => {
    it('should return all active store items', async () => {
      const response = await request(app)
        .get('/api/store/items')
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(Array.isArray(response.body.data)).toBe(true);
      expect(response.body.data.length).toBeGreaterThan(0);
    });

    it('should filter items by type', async () => {
      const response = await request(app)
        .get('/api/store/items/type/pixel_boost')
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.every(item => item.type === 'pixel_boost')).toBe(true);
    });
  });

  describe('POST /api/store/purchase', () => {
    beforeEach(async () => {
      // 模拟认证中间件
      authToken = 'test-token';
    });

    it('should purchase item with points successfully', async () => {
      const response = await request(app)
        .post('/api/store/purchase')
        .set('Authorization', `Bearer ${authToken}`)
        .set('X-Idempotency-Key', uuidv4())
        .send({
          itemId: testItem.id,
          quantity: 1,
          paymentMethod: 'points'
        })
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data).toHaveProperty('transaction');
    });

    it('should fail when user has insufficient points', async () => {
      // 设置用户积分为0
      await db('user_points').where('user_id', testUser.id).update({ total_points: 0 });

      const response = await request(app)
        .post('/api/store/purchase')
        .set('Authorization', `Bearer ${authToken}`)
        .set('X-Idempotency-Key', uuidv4())
        .send({
          itemId: testItem.id,
          quantity: 1,
          paymentMethod: 'points'
        })
        .expect(400);

      expect(response.body.success).toBe(false);
      expect(response.body.error).toContain('积分不足');
    });

    it('should handle idempotency correctly', async () => {
      const idempotencyKey = uuidv4();
      
      // 第一次请求
      const response1 = await request(app)
        .post('/api/store/purchase')
        .set('Authorization', `Bearer ${authToken}`)
        .set('X-Idempotency-Key', idempotencyKey)
        .send({
          itemId: testItem.id,
          quantity: 1,
          paymentMethod: 'points'
        })
        .expect(200);

      // 第二次相同请求应该返回相同结果
      const response2 = await request(app)
        .post('/api/store/purchase')
        .set('Authorization', `Bearer ${authToken}`)
        .set('X-Idempotency-Key', idempotencyKey)
        .send({
          itemId: testItem.id,
          quantity: 1,
          paymentMethod: 'points'
        })
        .expect(200);

      expect(response1.body.data.transaction.id).toBe(response2.body.data.transaction.id);
    });
  });

  describe('GET /api/store/inventory', () => {
    it('should return user inventory', async () => {
      const response = await request(app)
        .get('/api/store/inventory')
        .set('Authorization', `Bearer ${authToken}`)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(Array.isArray(response.body.data)).toBe(true);
    });
  });

  describe('POST /api/store/use', () => {
    it('should use item successfully', async () => {
      const response = await request(app)
        .post('/api/store/use')
        .set('Authorization', `Bearer ${authToken}`)
        .send({
          itemId: testItem.id,
          quantity: 1
        })
        .expect(200);

      expect(response.body.success).toBe(true);
    });
  });

  describe('GET /api/store/points', () => {
    it('should return user points', async () => {
      const response = await request(app)
        .get('/api/store/points')
        .set('Authorization', `Bearer ${authToken}`)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data).toHaveProperty('points');
      expect(typeof response.body.data.points).toBe('number');
    });
  });
});
